#include <vector>
#include <algorithm>

using namespace std;

struct Edge {
    int u;
    int v;
    int time;
};

struct Compare {
    bool operator()(Edge a, Edge b) {
        return a.time < b.time;
    }
};

int64_t solve(int64_t n, vector<vector<int64_t>> edges, int64_t k) {
    // Sort edges by time
    vector<Edge> edgeList;
    for (int i = 0; i < edges.size(); i++) {
        Edge e;
        e.u = edges[i][0];
        e.v = edges[i][1];
        e.time = edges[i][2];
        edgeList.push_back(e);
    }
    sort(edgeList.begin(), edgeList.end(), Compare());

    // Initialize DSU
    vector<int64_t> parent(n);
    vector<int64_t> rank(n);
    for (int i = 0; i < n; i++) {
        parent[i] = i;
        rank[i] = 1;
    }

    int64_t result = 0;
    int64_t components = n;

    for (int i = 0; i < edgeList.size(); i++) {
        int u = edgeList[i].u;
        int v = edgeList[i].v;
        int time = edgeList[i].time;

        int rootU = find(parent, u);
        int rootV = find(parent, v);

        if (rootU != rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else {
                parent[rootU] = rootV;
                if (rank[rootU] == rank[rootV]) {
                    rank[rootV]++;
                }
            }
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            result = time;
            break;
        }
    }

    return result;
}

int64_t find(vector<int64_t>& parent, int64_t x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}
